#### 1.2 修改 `AutoIterationEngine`

在 `src/auto-iteration.ts` 中添加 Dashboard 集成：

```typescript
// 在文件顶部添加导入
import { initDashboardNotifier, getDashboardNotifier } from './dashboard/integration';
import pino from 'pino';

export class AutoIterationEngine {
  // ... 现有字段 ...
  private dashboardNotifier: ReturnType<typeof initDashboardNotifier> | null = null;
  private logger: pino.Logger;

  constructor(config: Partial<IterationConfig> = {}) {
    // ... 现有代码 ...

    // 初始化日志
    this.logger = pino({
      level: 'info',
      transport: {
        target: 'pino-pretty',
        options: { colorize: true }
      }
    });

    // 尝试初始化 Dashboard 通知器
    try {
      this.dashboardNotifier = initDashboardNotifier(this.logger);
      this.logger.info('✅ Dashboard 通知器已初始化');
    } catch (error) {
      this.logger.warn({ error }, '⚠️ Dashboard 通知器初始化失败，将不使用实时通知');
    }
  }

  /**
   * 执行单次迭代 - Dashboard 集成版
   */
  private async runIteration(): Promise<void> {
    const startTime = Date.now();
    let task: string = '';

    try {
      // 🆕 通知迭代开始
      if (this.dashboardNotifier) {
        await this.dashboardNotifier.notifyIterationStart(
          this.iterationCount,
          '自主迭代任务'
        );
      }

      // Phase 1: 产品经理分析项目
      console.log('\n📋 Phase 1: 产品经理分析项目...');

      // 🆕 通知 Agent 开始
      if (this.dashboardNotifier) {
        await this.dashboardNotifier.notifyAgentStart(
          'product-manager',
          '分析项目并发现需求'
        );
      }

      const analysisPrompt = `分析项目并提一个小改进任务。
项目: ${this.config.projectPath}
要求: 提出一个具体的、小的改进任务。`;

      const analysisResult = await this.productManager.executeAndCollect(analysisPrompt);
      const shortAnalysis = analysisResult.substring(0, 300);
      console.log(`📊 分析结果: ${shortAnalysis}...`);

      // 提取任务
      task = this.extractTask(analysisResult);
      const shortTask = task.substring(0, 100);
      console.log(`\n🎯 本次任务: ${shortTask}`);

      // 🆕 通知 Agent 完成
      if (this.dashboardNotifier) {
        await this.dashboardNotifier.notifyAgentComplete(
          'product-manager',
          analysisResult,
          (Date.now() - startTime) / 1000,
          0 // TODO: 从 Agent 获取 token 使用量
        );
      }

      // Phase 2: 架构师设计
      console.log('\n🏗️ Phase 2: 架构师设计...');

      if (this.dashboardNotifier) {
        await this.dashboardNotifier.notifyAgentStart('architect', shortTask);
      }

      const designPrompt = `设计技术方案: ${shortTask}`;
      const designResult = await this.agents.architect.executeAndCollect(designPrompt);
      console.log('✅ 设计完成');

      if (this.dashboardNotifier) {
        await this.dashboardNotifier.notifyAgentComplete(
          'architect',
          designResult,
          30, // 估算时间
          0
        );
      }

      // Phase 3: 并行开发
      console.log('\n💻 Phase 3: 并行开发...');
      const devPrompt = `开发任务: ${shortTask}`;

      // 🆕 通知并行开发开始
      const frontendStart = this.dashboardNotifier?.notifyAgentStart('frontend', shortTask);
      const backendStart = this.dashboardNotifier?.notifyAgentStart('backend', shortTask);
      const databaseStart = this.dashboardNotifier?.notifyAgentStart('database', shortTask);
      const assetsStart = this.dashboardNotifier?.notifyAgentStart('assets', shortTask);

      await Promise.all([
        frontendStart || Promise.resolve(),
        backendStart || Promise.resolve(),
        databaseStart || Promise.resolve(),
        assetsStart || Promise.resolve()
      ]);

      const devResults = await Promise.allSettled([
        this.agents.frontend.executeAndCollect(devPrompt),
        this.agents.backend.executeAndCollect(devPrompt),
        this.agents.database.executeAndCollect(devPrompt),
        this.agents.assets.executeAndCollect(devPrompt),
      ]);

      const devCompleted = devResults.every(r => r.status === 'fulfilled');
      console.log(`✅ 开发完成 (${devCompleted ? '全部成功' : '部分失败'})`);

      // 🆕 通知并行开发完成
      devResults.forEach((result, index) => {
        const agentTypes = ['frontend', 'backend', 'database', 'assets'];
        const agentType = agentTypes[index];

        if (result.status === 'fulfilled' && this.dashboardNotifier) {
          this.dashboardNotifier!.notifyAgentComplete(
            agentType as any,
            result.value,
            60,
            0
          );
        } else if (result.status === 'rejected' && this.dashboardNotifier) {
          this.dashboardNotifier!.notifyAgentError(
            agentType as any,
            String(result.reason)
          );
        }
      });

      // Phase 4: 测试 + 安全 + 文档
      console.log('\n🧪 Phase 4: 测试 + 安全 + 文档...');
      const testPrompt = `任务: ${shortTask}`;

      const testResults = await Promise.allSettled([
        this.agents.tester.executeAndCollect(testPrompt),
        this.agents.security.executeAndCollect(testPrompt),
        this.agents.documenter.executeAndCollect(testPrompt),
      ]);

      const testCompleted = testResults.every(r => r.status === 'fulfilled');
      console.log(`✅ 测试/安全/文档完成 (${testCompleted ? '全部成功' : '部分失败'})`);

      // 🆕 通知测试阶段完成
      testResults.forEach((result, index) => {
        const agentTypes = ['tester', 'security', 'documenter'];
        const agentType = agentTypes[index];

        if (result.status === 'fulfilled' && this.dashboardNotifier) {
          this.dashboardNotifier!.notifyAgentComplete(
            agentType as any,
            result.value,
            30,
            0
          );
        }
      });

      // Phase 5: Git 提交
      let commitInfo: { commitId: string; files: number; lines: number } | null = null;
      if (this.config.autoCommit) {
        console.log('\n📦 Phase 5: Git 提交...');
        commitInfo = await this.gitCommit(shortTask);

        // 🆕 通知 Git 提交
        if (this.dashboardNotifier && commitInfo) {
          await this.dashboardNotifier.notifyGitCommit(
            commitInfo.commitId,
            shortTask,
            'main' // TODO: 获取实际分支
          );
        }
      }

      // 记录结果
      this.history.push({
        iteration: this.iterationCount,
        task: shortTask,
        status: 'success',
        message: commitInfo ? `${commitInfo.commitId} (${commitInfo.files}个文件, +${commitInfo.lines}行)` : '迭代完成',
        timestamp: new Date(),
      });

      console.log('\n✅ 迭代完成！');

      // 🆕 通知迭代完成
      if (this.dashboardNotifier) {
        await this.dashboardNotifier.notifyIterationComplete(
          designResult,
          analysisResult,
          devResults[0].status === 'fulfilled' ? devResults[0].value : undefined,
          devResults[1].status === 'fulfilled' ? devResults[1].value : undefined,
          devResults[2].status === 'fulfilled' ? devResults[2].value : undefined,
          devResults[3].status === 'fulfilled' ? devResults[3].value : undefined,
          testResults[0].status === 'fulfilled' ? testResults[0].value : undefined,
          testResults[1].status === 'fulfilled' ? testResults[1].value : undefined,
          testResults[2].status === 'fulfilled' ? testResults[2].value : undefined
        );
      }

      // 发送通知到飞书
      if (commitInfo) {
        await this.sendNotification(commitInfo);
      }

    } catch (error) {
      console.error('❌ 迭代失败:', error);

      // 🆕 通知迭代失败
      if (this.dashboardNotifier) {
        await this.dashboardNotifier.notifyIterationError(String(error));
      }

      this.history.push({
        iteration: this.iterationCount,
        task: task || 'unknown',
        status: 'failed',
        message: String(error),
        timestamp: new Date(),
      });
    }
  }
}
