## 🚀 四、技术改进方案

### 4.1 核心问题修复方案

#### 方案1: WebSocket 实时通信修复

**问题**: Dashboard 前端 WebSocket 未连接，无法接收实时数据

**解决方案**:

```typescript
// dashboard/src/services/websocket.ts
import { ref, onUnmounted } from 'vue'
import { useWebSocketStore } from '@/stores/websocket'
import { useIterationStore } from '@/stores/iteration'
import { useAgentStore } from '@/stores/agent'

export class DashboardWebSocket {
  private ws: WebSocket | null = null
  private reconnectTimer: number | null = null
  private reconnectAttempts = 0
  private maxReconnectAttempts = 5
  private wsStore = useWebSocketStore()
  private iterationStore = useIterationStore()
  private agentStore = useAgentStore()

  connect(url: string = 'ws://localhost:3000/api/ws') {
    if (this.ws?.readyState === WebSocket.OPEN) {
      console.log('WebSocket already connected')
      return
    }

    console.log('Connecting to WebSocket:', url)
    this.ws = new WebSocket(url)

    this.ws.onopen = () => {
      console.log('✅ WebSocket connected')
      this.wsStore.setConnected(true)
      this.reconnectAttempts = 0

      // 订阅所有频道
      this.subscribe('all')
    }

    this.ws.onmessage = (event) => {
      try {
        const { event: type, data } = JSON.parse(event.data)
        this.handleMessage(type, data)
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error)
      }
    }

    this.ws.onerror = (error) => {
      console.error('WebSocket error:', error)
      this.wsStore.setError(new Error('WebSocket connection error'))
    }

    this.ws.onclose = () => {
      console.log('WebSocket disconnected')
      this.wsStore.setConnected(false)
      this.attemptReconnect()
    }
  }

  private handleMessage(event: string, data: any) {
    switch (event) {
      case 'connected':
        console.log('🎉 Server acknowledgment:', data)
        break

      case 'iteration.status_changed':
        console.log('📊 Iteration status changed:', data)
        this.iterationStore.updateIteration(data)
        break

      case 'agent.status_changed':
        console.log('🤖 Agent status changed:', data)
        this.agentStore.updateAgent(data)
        break

      case 'iteration.progress':
        console.log('📈 Iteration progress:', data)
        this.iterationStore.updateProgress(data.progress)
        break

      case 'log.entry':
        console.log('📝 New log entry:', data)
        // TODO: 添加到日志store
        break

      case 'system.metrics':
        console.log('📊 System metrics:', data)
        this.iterationStore.updateMetrics(data)
        break

      default:
        console.log('Unhandled event:', event, data)
    }
  }

  private subscribe(channel: string) {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
      console.warn('Cannot subscribe: WebSocket not connected')
      return
    }

    this.ws.send(JSON.stringify({
      event: 'subscribe',
      data: { channel }
    }))
  }

  private attemptReconnect() {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      console.error('Max reconnect attempts reached')
      return
    }

    this.reconnectAttempts++
    const delay = Math.min(1000 * Math.pow(2, this.reconnectAttempts), 30000)

    console.log(`Reconnecting in ${delay}ms... (attempt ${this.reconnectAttempts})`)

    this.reconnectTimer = window.setTimeout(() => {
      this.connect()
    }, delay)
  }

  disconnect() {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer)
    }

    if (this.ws) {
      this.ws.close()
      this.ws = null
    }
  }
}

// 创建全局单例
export const wsClient = new DashboardWebSocket()

// Vue Composable
export function useWebSocket() {
  const connect = (url?: string) => wsClient.connect(url)
  const disconnect = () => wsClient.disconnect()

  onUnmounted(() => {
    disconnect()
  })

  return {
    connect,
    disconnect
  }
}
```

