### 4.2 系统架构优化方案

#### 优化1: 引入缓存层

```typescript
// 建议技术栈: Redis 或 Node-Cache
// 优化目标: 减少 API 调用，提升响应速度

interface CacheStrategy {
  // 系统概览缓存 (30秒)
  systemOverview: {
    ttl: 30,
    key: 'system:overview'
  },

  // 迭代列表缓存 (5秒)
  iterationList: {
    ttl: 5,
    key: 'iterations:list'
  },

  // Agent 状态缓存 (实时)
  agentStatus: {
    ttl: 1,
    key: 'agent:status'
  }
}

class CachedAPIClient {
  private cache: NodeCache
  private api: APIClient

  async getSystemOverview() {
    const cached = this.cache.get<CacheStrategy['systemOverview']>('system:overview')
    if (cached) return cached

    const data = await this.api.getSystemOverview()
    this.cache.set('system:overview', data, 30)
    return data
  }
}
```

#### 优化2: 消息队列异步化

```typescript
// 建议技术栈: Bull (Redis-based) 或内存队列
// 优化目标: 解耦 Agent 执行，支持后台任务

import { Queue, Worker } from 'bull'

class AgentTaskQueue {
  private queue: Queue

  constructor() {
    this.queue = new Queue('agent-tasks', 'redis://localhost:6379')

    // 启动 Worker
    this.startWorker()
  }

  async scheduleAgentTask(agentName: string, task: any) {
    await this.queue.add(agentName, task, {
      attempts: 3,
      backoff: {
        type: 'exponential',
        delay: 1000
      }
    })
  }

  private startWorker() {
    const worker = new Worker('agent-tasks', async (job) => {
      const agent = this.getAgent(job.name)
      return await agent.execute(job.data)
    })

    worker.on('completed', (job) => {
      console.log(`✅ Task ${job.id} completed`)
    })
  }
}
```

