##### 1. **新增 IterationControlService** (控制服务)

**文件**: `src/dashboard/services/control.service.ts`

```typescript
/**
 * 迭代控制服务 - 管理 AutoIterationEngine 的生命周期
 */

import { Logger } from 'pino';
import { AutoIterationEngine } from '../../auto-iteration';
import { RealtimeService } from './realtime.service';

// ==================== 控制命令 ====================

export enum ControlCommand {
  START = 'start',
  PAUSE = 'pause',
  RESUME = 'resume',
  STOP = 'stop',
  STATUS = 'status'
}

// ==================== 引擎状态 ====================

export enum EngineState {
  IDLE = 'idle',           // 未启动
  RUNNING = 'running',     // 运行中
  PAUSED = 'paused',       // 已暂停
  STOPPING = 'stopping',   // 停止中
  STOPPED = 'stopped',     // 已停止
  ERROR = 'error'          // 错误
}

// ==================== 控制结果 ====================

export interface ControlResult {
  success: boolean;
  state: EngineState;
  message: string;
  timestamp: Date;
}

// ==================== 控制配置 ====================

export interface ControlConfig {
  projectPath: string;
  intervalMs?: number;
  maxIterations?: number;
  autoCommit?: boolean;
  autoPush?: boolean;
}

// ==================== 迭代控制服务 ====================

export class IterationControlService {
  private engine: AutoIterationEngine | null = null;
  private state: EngineState = EngineState.IDLE;
  private currentIteration: number = 0;

  constructor(
    private logger: Logger,
    private realtimeService: RealtimeService
  ) {}

  /**
   * 启动引擎
   */
  async start(config: ControlConfig): Promise<ControlResult> {
    try {
      // 检查是否已在运行
      if (this.state === EngineState.RUNNING) {
        return {
          success: false,
          state: this.state,
          message: '引擎已在运行中',
          timestamp: new Date()
        };
      }

      // 如果引擎不存在,创建新实例
      if (!this.engine) {
        this.logger.info('Creating new AutoIterationEngine instance');
        this.engine = new AutoIterationEngine({
          projectPath: config.projectPath,
          intervalMs: config.intervalMs || 60000,
          maxIterations: config.maxIterations || 0,
          autoCommit: config.autoCommit ?? true,
          autoPush: config.autoPush ?? true,
          permissionMode: 'bypassPermissions'
        });
      }

      // 更新状态
      this.state = EngineState.RUNNING;
      this.broadcastStateChange();

      // 启动引擎(非阻塞)
      this.engine.start().catch((error) => {
        this.logger.error(error, 'Engine failed to start');
        this.state = EngineState.ERROR;
        this.broadcastStateChange();
      });

      this.logger.info('AutoIterationEngine started');

      return {
        success: true,
        state: this.state,
        message: '引擎已启动',
        timestamp: new Date()
      };

    } catch (error) {
      this.logger.error(error, 'Failed to start engine');
      this.state = EngineState.ERROR;

      return {
        success: false,
        state: this.state,
        message: `启动失败: ${error.message}`,
        timestamp: new Date()
      };
    }
  }

  /**
   * 暂停引擎
   */
  pause(): ControlResult {
    if (this.state !== EngineState.RUNNING) {
      return {
        success: false,
        state: this.state,
        message: '引擎未在运行中',
        timestamp: new Date()
      };
    }

    // AutoIterationEngine 需要支持暂停
    // 暂时使用 stop() 作为替代
    if (this.engine) {
      this.engine.stop();
    }

    this.state = EngineState.PAUSED;
    this.broadcastStateChange();

    this.logger.info('AutoIterationEngine paused');

    return {
      success: true,
      state: this.state,
      message: '引擎已暂停',
      timestamp: new Date()
    };
  }

  /**
   * 恢复引擎
   */
  async resume(): Promise<ControlResult> {
    if (this.state !== EngineState.PAUSED) {
      return {
        success: false,
        state: this.state,
        message: '引擎未处于暂停状态',
        timestamp: new Date()
      };
    }

    // 重新启动引擎
    if (this.engine) {
      this.state = EngineState.RUNNING;
      this.broadcastStateChange();

      this.engine.start().catch((error) => {
        this.logger.error(error, 'Engine failed to resume');
        this.state = EngineState.ERROR;
        this.broadcastStateChange();
      });

      return {
        success: true,
        state: this.state,
        message: '引擎已恢复运行',
        timestamp: new Date()
      };
    }

    return {
      success: false,
      state: this.state,
      message: '引擎实例不存在',
      timestamp: new Date()
    };
  }

  /**
   * 停止引擎
   */
  stop(): ControlResult {
    if (this.state === EngineState.IDLE || this.state === EngineState.STOPPED) {
      return {
        success: false,
        state: this.state,
        message: '引擎未运行',
        timestamp: new Date()
      };
    }

    this.state = EngineState.STOPPING;
    this.broadcastStateChange();

    if (this.engine) {
      this.engine.stop();
    }

    this.state = EngineState.STOPPED;
    this.broadcastStateChange();

    this.logger.info('AutoIterationEngine stopped');

    return {
      success: true,
      state: this.state,
      message: '引擎已停止',
      timestamp: new Date()
    };
  }

  /**
   * 获取当前状态
   */
  getStatus(): {
    state: EngineState;
    iteration: number;
    isRunning: boolean;
  } {
    return {
      state: this.state,
      iteration: this.currentIteration,
      isRunning: this.state === EngineState.RUNNING
    };
  }

  /**
   * 重置引擎(用于清理和重新开始)
   */
  reset(): void {
    if (this.engine) {
      this.engine.stop();
      this.engine = null;
    }

    this.state = EngineState.IDLE;
    this.currentIteration = 0;
    this.broadcastStateChange();

    this.logger.info('AutoIterationEngine reset');
  }

  // ==================== 私有方法 ====================

  /**
   * 广播状态变化
   */
  private broadcastStateChange(): void {
    this.realtimeService.broadcast({
      event: 'engine.state_changed',
      data: {
        state: this.state,
        iteration: this.currentIteration,
        timestamp: new Date()
      }
    });
  }
}
```

