##### 2. **更新 WebSocket 处理逻辑**

**修改文件**: `src/dashboard/server.ts`

```typescript
// 导入控制服务
import { IterationControlService, ControlCommand } from './services/control.service';

// 在服务实例声明中添加
let controlService: IterationControlService;

// 在初始化服务部分添加
controlService = new IterationControlService(logger, realtimeService);

// 更新 handleWebSocketAction 函数
function handleWebSocketAction(data: any, socket: any) {
  const { event, action, channel, command } = data;

  switch (event || action) {
    case 'subscribe':
      logger.info({ channel }, 'Client subscribed to channel');
      realtimeService.subscribe(socket, channel || 'all');
      break;

    case 'unsubscribe':
      logger.info({ channel }, 'Client unsubscribed from channel');
      if (channel) {
        realtimeService.unsubscribe(socket, channel);
      }
      break;

    case 'control':
      handleControlCommand(data);
      break;

    case 'ping':
      break;

    default:
      logger.debug({ event, action }, 'WebSocket message received (no action needed)');
  }
}

/**
 * 处理控制命令
 */
async function handleControlCommand(data: any) {
  const { command, config } = data;
  let result;

  logger.info({ command }, 'Processing control command');

  switch (command) {
    case ControlCommand.START:
      result = await controlService.start(config || {
        projectPath: process.cwd()
      });
      break;

    case ControlCommand.PAUSE:
      result = controlService.pause();
      break;

    case ControlCommand.RESUME:
      result = await controlService.resume();
      break;

    case ControlCommand.STOP:
      result = controlService.stop();
      break;

    case ControlCommand.STATUS:
      result = {
        success: true,
        ...controlService.getStatus()
      };
      break;

    default:
      result = {
        success: false,
        message: `未知命令: ${command}`
      };
  }

  // 广播命令结果
  realtimeService.broadcast({
    event: 'engine.command_result',
    data: result
  });
}

// 在 getServices() 中导出控制服务
export function getServices() {
  return {
    iterationService,
    agentService,
    projectService,
    systemService,
    realtimeService,
    controlService  // 新增
  };
}
