#### 📊 API 接口设计

##### WebSocket 协议

**客户端 → 服务器**:

```typescript
// 启动引擎
{
  "event": "control",
  "command": "start",
  "config": {
    "projectPath": "/path/to/project",
    "intervalMs": 60000,
    "maxIterations": 10
  }
}

// 暂停引擎
{
  "event": "control",
  "command": "pause"
}

// 恢复引擎
{
  "event": "control",
  "command": "resume"
}

// 停止引擎
{
  "event": "control",
  "command": "stop"
}

// 查询状态
{
  "event": "control",
  "command": "status"
}
```

**服务器 → 客户端**:

```typescript
// 状态变化通知
{
  "event": "engine.state_changed",
  "data": {
    "state": "running",
    "iteration": 3,
    "timestamp": "2026-03-01T10:30:00Z"
  }
}

// 命令执行结果
{
  "event": "engine.command_result",
  "data": {
    "success": true,
    "state": "running",
    "message": "引擎已启动",
    "timestamp": "2026-03-01T10:30:00Z"
  }
}
```

